$_MODULE['<{PrestashopAPI}prestashop>801ab24683a4a8c433c6eb40c48bcd9d'] = 'Download';
$_MODULE['<{PrestashopAPI}prestashop>d4eb463703a7e5de947f59c53ef36bfa'] = 'No invoices returned by the marketplace for this period.';
$_MODULE['<{PrestashopAPI}prestashop>1c1325208aa668df5ebd5590d78559b1'] = 'Add your API key to see your payouts.';
$_MODULE['<{PrestashopAPI}prestashop>9cf3cea9fc2559bc3932a1034a8c77bd'] = 'Keep the data fresh automatically';
$_MODULE['<{PrestashopAPI}prestashop>70fab415490de4d1c4d958b059ff1cbf'] = 'The storefront badge and the figures above are read from a local copy of your marketplace data, so that no visitor to your shop ever waits for the marketplace. That copy refreshes when you open this page. To refresh it on a schedule instead, call this URL from a cron task, for example once an hour:';
$_MODULE['<{PrestashopAPI}prestashop>9b4fe89ace5fbb71472cf7a6c3c0ffe9'] = 'Keep this URL private: anyone who has it can trigger a refresh. It changes if you reinstall the module.';
$_MODULE['<{PrestashopAPI}prestashop>850d45fc61bfd3cd575cbc45addd9529'] = 'Cached data';
$_MODULE['<{PrestashopAPI}prestashop>058881da8f789da85e445bfd42bdee3c'] = 'If something looks wrong, clear the local copy and download everything again.';
$_MODULE['<{PrestashopAPI}prestashop>dc034e19f7696e490bc7229a3f70142c'] = 'Clear cached data';
$_MODULE['<{PrestashopAPI}prestashop>3b488ade6f134eacce53039c0d3b7908'] = 'How this module works';
$_MODULE['<{PrestashopAPI}prestashop>2b567533f379fab2c398929de7c99c2e'] = 'Where the numbers come from';
$_MODULE['<{PrestashopAPI}prestashop>1438971d29f373379a0ca6b9e82f04b0'] = 'Marketplace figures are downloaded from the PrestaShop Addons Seller API with your own API key, and stored locally. Your shop figures are read from your own valid orders. Nothing is sent anywhere else.';
$_MODULE['<{PrestashopAPI}prestashop>e9ac528d46587d227713f545b102975e'] = 'Why some products show no shop sales';
$_MODULE['<{PrestashopAPI}prestashop>3585339aed30ba73e0e738d458cff45e'] = 'The module needs to know which product in your catalogue is the same as which product on the marketplace. It matches them when the reference of your product equals the marketplace product ID. If you use different references, pin them by hand on the Products tab.';
$_MODULE['<{PrestashopAPI}prestashop>53beb26d8bca00f56fbd295fdee83459'] = 'Refunds';
$_MODULE['<{PrestashopAPI}prestashop>de980f4d92dea658e437fb1a6db084fd'] = 'Refunded units are subtracted from both units and revenue, on both sides, so the totals are what you actually kept.';
$_MODULE['<{PrestashopAPI}prestashop>dfcfc43722eef1eab1e4a12e50a068b1'] = 'Currencies';
$_MODULE['<{PrestashopAPI}prestashop>9bd1ea4499517071a96ee0340edeccf5'] = 'Marketplace payouts are usually in euros while your shop may sell in another currency. Combined totals use your shop exchange rate. If your shop has no rate for the marketplace currency, combined totals are hidden rather than guessed.';
$_MODULE['<{PrestashopAPI}prestashop>9635c7ca9186a5b541c68c3e54afc07d'] = 'The storefront badge';
$_MODULE['<{PrestashopAPI}prestashop>8224e1ccb8232fe6f2ccd4fbeb8c2374'] = 'Optionally, product pages in your own shop can show how many times a product has been downloaded, as social proof. It is drawn from the local copy of your data, costs no extra page time, and hides itself below the threshold you set.';
$_MODULE['<{PrestashopAPI}prestashop>44877c6aa8e93fa5a91c9361211464fb'] = 'Speed';
$_MODULE['<{PrestashopAPI}prestashop>803e2b0d8f5afc76e2e54fad606490c0'] = 'A wide reporting period means more rows to download. If refreshing feels slow, narrow the period or lengthen the refresh interval in Settings.';
$_MODULE['<{PrestashopAPI}prestashop>8b9c1abd043bde61211bc6d58be58370'] = 'If something does not work';
$_MODULE['<{PrestashopAPI}prestashop>f2cb075d74e523731af10acbb1177695'] = 'Your server could not open an outgoing HTTPS connection to the marketplace. Shared hosts often block this. The Status list on the Dashboard tab tells you whether cURL itself is available; if it is, ask your host whether outgoing connections to api.addons.prestashop.com are allowed.';
$_MODULE['<{PrestashopAPI}prestashop>f64dc4589dc99c8b6633332d2cd64673'] = 'Generate a fresh key in your seller account, under Settings then API, and paste it again. Copy only the key, not the surrounding text.';
$_MODULE['<{PrestashopAPI}prestashop>e42e9d958504c5158fe91c5d56ee6214'] = 'The figures are older than they should be';
$_MODULE['<{PrestashopAPI}prestashop>cce5ffc741270470dec823a4fff75552'] = 'Shop sales are zero for every product';
$_MODULE['<{PrestashopAPI}prestashop>95dab330ce5b2c1d94467c07916fea17'] = 'None of your marketplace products matched a product in your catalogue. Check the Status list on the Dashboard tab, and pin the products by hand on the Products tab.';
$_MODULE['<{PrestashopAPI}prestashop>e67411c887a32a48389e48e21d409fca'] = 'What the API returns';
$_MODULE['<{PrestashopAPI}prestashop>9d0b331fa4855d2fc2b8ffca416cc545'] = 'The marketplace only documents its products and sales data. Everything else, including conversations, invoices and payouts, is read from fields whose names we have had to infer. This shows one real row from each endpoint of your own account, so the module can be matched to what your account actually sends.';
$_MODULE['<{PrestashopAPI}prestashop>8c97b6869b7a8ca6c4d6ec89ea13cbe0'] = 'This is live data from your seller account and may contain buyer names or e-mail addresses. Remove anything personal before sharing it.';
$_MODULE['<{PrestashopAPI}prestashop>1ad29d73a1351f6885ba5f406942f35c'] = 'Show one sample row from each endpoint';
